DECLARE
  CURSOR c_emp IS SELECT ENAME FROM EMP;
  v_ename EMP.ENAME%TYPE;
BEGIN
  OPEN c_emp;
  LOOP
    FETCH c_emp INTO v_ename;
    EXIT WHEN c_emp%NOTFOUND;
    DBMS_OUTPUT.PUT_LINE(v_ename);
  END LOOP;
  CLOSE c_emp;
END;

DECLARE
  CURSOR c_sal IS SELECT ENAME, SAL FROM EMP;
  v_name EMP.ENAME%TYPE; v_sal EMP.SAL%TYPE;
BEGIN
  OPEN c_sal;
  LOOP
    FETCH c_sal INTO v_name, v_sal;
    EXIT WHEN c_sal%NOTFOUND;
    DBMS_OUTPUT.PUT_LINE(v_name || ' ' || v_sal);
  END LOOP;
  CLOSE c_sal;
END;

DECLARE
  CURSOR c_high IS SELECT ENAME FROM EMP WHERE SAL > 3000;
  v_name EMP.ENAME%TYPE;
BEGIN
  OPEN c_high;
  LOOP
    FETCH c_high INTO v_name;
    EXIT WHEN c_high%NOTFOUND;
    DBMS_OUTPUT.PUT_LINE(v_name);
  END LOOP;
  CLOSE c_high;
END;

DECLARE
  CURSOR c_tot IS SELECT SAL FROM EMP;
  v_sal NUMBER; v_total NUMBER := 0;
BEGIN
  OPEN c_tot;
  LOOP
    FETCH c_tot INTO v_sal;
    EXIT WHEN c_tot%NOTFOUND;
    v_total := v_total + v_sal;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE(v_total);
  CLOSE c_tot;
END;

DECLARE
  CURSOR c_count IS SELECT * FROM EMP;
  v_rec EMP%ROWTYPE;
BEGIN
  OPEN c_count;
  LOOP
    FETCH c_count INTO v_rec;
    EXIT WHEN c_count%NOTFOUND;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE(c_count%ROWCOUNT);
  CLOSE c_count;
END;

