DECLARE
  CURSOR c_dsal (p_d NUMBER) IS SELECT SAL FROM EMP WHERE DEPTNO = p_d;
  v_sum NUMBER := 0;
BEGIN
  FOR r IN c_dsal(10) LOOP
    v_sum := v_sum + r.sal;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE(v_sum);
END;

DECLARE
  CURSOR c_upd IS SELECT SAL FROM EMP FOR UPDATE;
BEGIN
  FOR r IN c_upd LOOP
    UPDATE EMP SET SAL = SAL + 10 WHERE CURRENT OF c_upd;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE('Updated');
END;

DECLARE
  CURSOR c_curr IS SELECT SAL FROM EMP WHERE JOB = 'CLERK' FOR UPDATE;
BEGIN
  FOR r IN c_curr LOOP
    UPDATE EMP SET SAL = SAL * 1.1 WHERE CURRENT OF c_curr;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE('Bonus Updated');
END;

DECLARE
  CURSOR c_del IS SELECT SAL FROM EMP WHERE SAL < 2000 FOR UPDATE;
BEGIN
  FOR r IN c_del LOOP
    DELETE FROM EMP WHERE CURRENT OF c_del;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE('Rows Deleted');
END;

DECLARE
  CURSOR c_j IS SELECT JOB FROM EMP WHERE JOB = 'SALESMAN' FOR UPDATE;
BEGIN
  FOR r IN c_j LOOP
    UPDATE EMP SET JOB = 'SALES_REP' WHERE CURRENT OF c_j;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE('Jobs Updated');
END;

DECLARE
  CURSOR c_v IS SELECT ENAME, SAL FROM EMP FOR UPDATE;
BEGIN
  FOR r IN c_v LOOP
    UPDATE EMP SET SAL = SAL + 5 WHERE CURRENT OF c_v;
    DBMS_OUTPUT.PUT_LINE(r.ename || ' modified');
  END LOOP;
END;

DECLARE
  CURSOR c_top IS SELECT ENAME, SAL FROM EMP ORDER BY SAL DESC;
  v_n VARCHAR2(20); v_s NUMBER;
BEGIN
  OPEN c_top;
  FOR i IN 1..3 LOOP
    FETCH c_top INTO v_n, v_s;
    DBMS_OUTPUT.PUT_LINE(v_n || ' ' || v_s);
  END LOOP;
  CLOSE c_top;
END;

DECLARE
  CURSOR c_p IS SELECT ENAME FROM EMP;
  v_n VARCHAR2(20);
BEGIN
  OPEN c_p;
  FOR i IN 1..7 LOOP
    FETCH c_p INTO v_n;
    IF i >= 5 THEN
      DBMS_OUTPUT.PUT_LINE(v_n);
    END IF;
  END LOOP;
  CLOSE c_p;
END;

